class Solution:
    def maximumPrimeDifference(self, nums):
        def isp(v):
            if v < 2:
                return False
            d = 2
            while d * d <= v:
                if v % d == 0:
                    return False
                d += 1
            return True
        idx = [i for i, v in enumerate(nums) if isp(v)]
        return idx[-1] - idx[0]

